  stage_name character varying(100) NOT NULL,
  description text,
  phase_number integer NOT NULL,
  phase_name character varying(50) NOT NULL,
  work_type character varying(30) NOT NULL,
  sd_required boolean DEFAULT false,
  sd_suffix character varying(20),
  advisory_enabled boolean DEFAULT false,
