iorities, and operational handoff to the Operations dashboard for ongoing monitoring.","phase_number":6,"phase_name":"LAUNCH & GROW","work_type":"artifact_only","sd_required":false,"sd_suffix":null,"advisory_enabled":false,"depends_on":[25],"required_artifacts":["growth_playbook","growth_optimization_roadmap"],"metadata":{"gates":{"exit":["growth_playbook","growth_optimization_roadmap"]},"outputs":["growth_experiments","scaling_priorities","operations_handoff"],"feeds_into":"operations_dashboard"},"created_at":"2025-12-07T00:06:01.097454+00:00","updated_at":"2026-04-21T23:20:37.922731+00:00"},{"stage_number":20,"stage_name":"Code Quality Gate","description":"Claude Code validates the actual GitHub repo: npm audit, secret detection, lint, test suite execution. Produces pass/fail quality report. Blocks advancement if critical issues found.","phase_number":5,"phase_name":"BUILD & MARKET","work_type":"automated_check","sd_required":false,"sd_suffix":null,"advisory_enabled":false,"depends_on":[19],"required_artifacts":["code_quality_report"],"metadata":{"gates":{"exit":["No critical security issues","No exposed secrets","Lint passes"]},"validation_methods":["npm_audit","secret_detection","lint","test_suite"]},"created_at":"2025-12-07T00:06:01.097454+00:00","updated_at":"2026-04-21T23:20:37.922731+00:00"},{"stage_number":21,"stage_name":"Visual Assets","description":"Generate device-framed screenshots from live app, social media graphics sized per platform, and video storyboard cards. Uses S17 approved designs and the built application.","phase_number":5,"phase_name":"BUILD & MARKET","work_type":"artifact_only","sd_required":false,"sd_suffix":null,"advisory_enabled":false,"depends_on":[20],"required_artifacts":["visual_device_screenshots","visual_social_graphics"],"metadata":{"asset_types":["device_screenshots","social_graphics","video_storyboards"],"social_sizes":["instagram_square","twitter_banner","facebook_cover"],"device_frames":["iphone","macbook"]},"created_at":"20