Design Studio: wireframe generation, visual convergence, and design materialization. Translates technical architecture into visual design artifacts.","phase_number":4,"phase_name":"THE_BLUEPRINT","work_type":"artifact_only","sd_required":true,"sd_suffix":null,"advisory_enabled":false,"depends_on":[14],"required_artifacts":["wireframe_screens"],"metadata":{"metrics":{"invest_compliance":true},"stage_timeout_ms":600000},"created_at":"2025-12-07T00:06:01.097454+00:00","updated_at":"2026-05-25T12:31:01.879+00:00"},{"stage_number":14,"stage_name":"Technical Architecture","description":"Entity relationship design, schema architecture, data flow planning, and risk register creation. Consolidates technical blueprinting with risk assessment to provide a complete engineering foundation before design materialization.","phase_number":4,"phase_name":"THE_BLUEPRINT","work_type":"artifact_only","sd_required":true,"sd_suffix":"DATAMODEL","advisory_enabled":false,"depends_on":[13],"required_artifacts":["blueprint_technical_architecture","blueprint_data_model","blueprint_erd_diagram","blueprint_api_contract","blueprint_schema_spec"],"metadata":{},"created_at":"2025-12-07T00:06:01.097454+00:00","updated_at":"2026-05-26T20:19:16.55913+00:00"},{"stage_number":9,"stage_name":"Exit Strategy","description":"Strategic exit planning, valuation targets, and acquisition-friendly architecture.","phase_number":2,"phase_name":"THE_ENGINE","work_type":"artifact_only","sd_required":false,"sd_suffix":null,"advisory_enabled":false,"depends_on":[8],"required_artifacts":["engine_exit_strategy"],"metadata":{},"created_at":"2025-12-07T00:06:01.097454+00:00","updated_at":"2025-12-07T00:06:01.097454+00:00"},{"stage_number":10,"stage_name":"Customer & Brand Foundation","description":"Brand naming, identity development, and guidelines creation.","phase_number":3,"phase_name":"THE_IDENTITY","work_type":"sd_required","sd_required":true,"sd_suffix":"BRAND","advisory_enabled":false,"depends_on":[9],"required_art